#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

int T,n,p[11],cnt,inv,ans;

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int cal(int d){
    int res=n/d;
    for(int i=1;i<=cnt;i++)
        if(n/d%p[i]==0)
            res=res/p[i]*(p[i]-1);
    return 1ll*res*qpow(n,d)%mod;
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d",&n);
        int num=n;
        cnt=0;
        for(int i=2;i*i<=num;i++)
            if(num%i==0){
                while(num%i==0) num/=i;
                p[++cnt]=i;
            }
        if(num>1) p[++cnt]=num;
        inv=qpow(n,mod-2);
        ans=0;
        for(int i=1;i*i<=n;i++)
            if(n%i==0){
                ans=(ans+cal(i))%mod;
                if(n/i!=i)
                    ans=(ans+cal(n/i))%mod;
            }
        printf("%d\n",1ll*ans*inv%mod);
    }
    return 0;
}
